function parseOptions(opts: string | null): string[] | null {
  if (!opts) return null
  try {
    const parsed = JSON.parse(opts)
    return Array.isArray(parsed) ? (parsed as string[]) : null
  } catch {
    return null
  }
}

interface AnswersSectionProps {
