interface AnswerRowProps {
  registrationId: string
  competitionId: string
  question: AthleteDetailQuestion
  member: AthleteDetailMember
  showMemberLabel: boolean
  currentAnswer: string
}

function AnswerRow({
  registrationId,
  competitionId,
  question,
  member,
  showMemberLabel,
  currentAnswer,
}: AnswerRowProps) {
  const router = useRouter()
  const updateAnswer = useServerFn(updateRegistrationAnswerFn)
  const [editing, setEditing] = useState(false)
  const [value, setValue] = useState(currentAnswer)
  const [isSaving, setIsSaving] = useState(false)

  const handleSave = async () => {
    setIsSaving(true)
    try {
      await updateAnswer({
        data: {
          registrationId,
          competitionId,
          userId: member.userId,
          questionId: question.id,
          answer: value,
        },
      })
      toast.success("Answer saved")
      setEditing(false)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to save answer",
      )
    } finally {
      setIsSaving(false)
    }
  }

  const handleCancel = () => {
    setValue(currentAnswer)
    setEditing(false)
  }

  return (
    <div className="flex items-start gap-3 py-2">
      {showMemberLabel && (
        <div className="text-xs text-muted-foreground w-32 shrink-0 pt-2 truncate">
          {memberDisplayName(member)}
        </div>
      )}
      <div className="flex-1 min-w-0">
        {editing ? (
          <div className="flex items-start gap-2">
            {question.type === "select" && parseOptions(question.options) ? (
              <div className="flex items-center gap-1 max-w-md flex-1">
                <Select value={value} onValueChange={setValue}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select an option" />
                  </SelectTrigger>
                  <SelectContent>
                    {(parseOptions(question.options) ?? []).map((opt) => (
                      <SelectItem key={opt} value={opt}>
                        {opt}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {value && (
                  <Button
                    size="icon"
                    variant="ghost"
                    type="button"
                    onClick={() => setValue("")}
                    disabled={isSaving}
                    aria-label="Clear selection"
                    className="h-9 w-9 shrink-0"
                  >
                    <X className="h-4 w-4" />
                  </Button>
                )}
              </div>
            ) : question.type === "number" ? (
              <Input
                type="number"
                value={value}
                onChange={(e) => setValue(e.target.value)}
                disabled={isSaving}
                className="max-w-md"
              />
            ) : value.length > 60 ? (
              <Textarea
                value={value}
                onChange={(e) => setValue(e.target.value)}
                disabled={isSaving}
                rows={3}
                className="max-w-md"
              />
            ) : (
              <Input
                value={value}
                onChange={(e) => setValue(e.target.value)}
                disabled={isSaving}
                className="max-w-md"
              />
            )}
            <Button
              size="icon"
              variant="outline"
              onClick={handleSave}
              disabled={isSaving}
              aria-label="Save answer"
              className="h-9 w-9 shrink-0"
            >
              <Check className="h-4 w-4" />
            </Button>
            <Button
              size="icon"
              variant="ghost"
              onClick={handleCancel}
              disabled={isSaving}
              aria-label="Cancel"
              className="h-9 w-9 shrink-0"
            >
              <X className="h-4 w-4" />
            </Button>
          </div>
        ) : (
          <button
            type="button"
            onClick={() => setEditing(true)}
            className="group flex items-start gap-2 text-left w-full rounded-md hover:bg-muted/50 -mx-2 px-2 py-1.5"
          >
            <span
              className={
                currentAnswer
                  ? "text-sm flex-1"
                  : "text-sm italic text-muted-foreground flex-1"
              }
            >
              {currentAnswer || "Not answered"}
            </span>
            <Pencil className="h-3.5 w-3.5 text-muted-foreground opacity-0 group-hover:opacity-100 mt-0.5 shrink-0" />
          </button>
        )}
      </div>
    </div>
  )
}

