import { Label } from "@/components/ui/label"
import {
  updateAthleteUserProfileFn,
  updateRegistrationAffiliateAsOrganizerFn,
} from "@/server-fns/organizer-athlete-fns"
import type { AthleteDetailMember } from "./types"
import { memberDisplayName, memberInitials } from "./types"

interface AthleteProfileCardProps {
  member: AthleteDetailMember
  affiliate: string | null
  registrationId: string
  competitionId: string
  onRemove?: () => void
}

export function AthleteProfileCard({
  member,
  affiliate,
  registrationId,
  competitionId,
  onRemove,
}: AthleteProfileCardProps) {
  const router = useRouter()
  const updateProfile = useServerFn(updateAthleteUserProfileFn)
  const updateAffiliate = useServerFn(updateRegistrationAffiliateAsOrganizerFn)

  const [editing, setEditing] = useState(false)
  const [firstName, setFirstName] = useState(member.firstName ?? "")
  const [lastName, setLastName] = useState(member.lastName ?? "")
  const [email, setEmail] = useState(member.email)
  const [affiliateInput, setAffiliateInput] = useState(affiliate ?? "")
  const [isSaving, setIsSaving] = useState(false)

  const handleSave = async () => {
    const profilePayload: {
      registrationId: string
      competitionId: string
      userId: string
      firstName?: string
      lastName?: string
      email?: string
    } = {
      registrationId,
      competitionId,
      userId: member.userId,
    }
    if (firstName.trim() && firstName.trim() !== (member.firstName ?? "")) {
      profilePayload.firstName = firstName.trim()
    }
    if (lastName.trim() && lastName.trim() !== (member.lastName ?? "")) {
      profilePayload.lastName = lastName.trim()
    }
    if (email.trim() && email.trim() !== member.email) {
      profilePayload.email = email.trim()
    }

    const profileChanged =
      profilePayload.firstName !== undefined ||
      profilePayload.lastName !== undefined ||
      profilePayload.email !== undefined

    const trimmedAffiliate = affiliateInput.trim()
    const currentAffiliate = affiliate ?? ""
    const affiliateChanged = trimmedAffiliate !== currentAffiliate

    if (!profileChanged && !affiliateChanged) {
      setEditing(false)
      return
    }

    setIsSaving(true)
    try {
      await Promise.all([
        profileChanged
          ? updateProfile({ data: profilePayload })
          : Promise.resolve(),
        affiliateChanged
          ? updateAffiliate({
              data: {
                registrationId,
                competitionId,
                userId: member.userId,
                affiliateName: trimmedAffiliate || null,
              },
            })
          : Promise.resolve(),
      ])
      toast.success("Profile updated")
      setEditing(false)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to update profile",
      )
    } finally {
      setIsSaving(false)
    }
  }

  const handleCancel = () => {
    setFirstName(member.firstName ?? "")
    setLastName(member.lastName ?? "")
    setEmail(member.email)
    setAffiliateInput(affiliate ?? "")
    setEditing(false)
  }

  const displayAffiliate = affiliate || "Independent"

  return (
    <Card>
      <CardHeader className="pb-3">
        <div className="flex items-start justify-between gap-3">
          <div className="flex items-center gap-3 min-w-0">
            <Avatar className="h-11 w-11">
              <AvatarImage
                src={member.avatar ?? undefined}
                alt={memberDisplayName(member)}
              />
              <AvatarFallback>{memberInitials(member)}</AvatarFallback>
            </Avatar>
            <div className="min-w-0">
              <div className="font-semibold truncate">
                {memberDisplayName(member)}
              </div>
              <div className="flex items-center gap-1.5 mt-1">
                {member.isCaptain ? (
                  <Badge variant="secondary" className="text-xs">
                    Captain
                  </Badge>
                ) : (
                  <Badge variant="outline" className="text-xs">
                    Teammate
                  </Badge>
                )}
                {!member.isActive && (
                  <Badge variant="destructive" className="text-xs">
                    Inactive
                  </Badge>
                )}
              </div>
            </div>
          </div>
          {!editing && (
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setEditing(true)}
              aria-label="Edit athlete profile"
              className="h-8 w-8 shrink-0"
            >
              <Pencil className="h-3.5 w-3.5" />
            </Button>
          )}
        </div>
      </CardHeader>
      <CardContent className="space-y-3">
        {editing ? (
          <>
            <div className="grid gap-3 sm:grid-cols-2">
              <div className="space-y-1.5">
                <Label
                  htmlFor={`fn-${member.userId}`}
                  className="text-xs uppercase tracking-wide text-muted-foreground"
                >
                  First name
                </Label>
                <Input
                  id={`fn-${member.userId}`}
                  value={firstName}
                  onChange={(e) => setFirstName(e.target.value)}
                  disabled={isSaving}
                />
              </div>
              <div className="space-y-1.5">
                <Label
                  htmlFor={`ln-${member.userId}`}
                  className="text-xs uppercase tracking-wide text-muted-foreground"
                >
                  Last name
                </Label>
                <Input
                  id={`ln-${member.userId}`}
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  disabled={isSaving}
                />
              </div>
            </div>
            <div className="space-y-1.5">
              <Label
                htmlFor={`em-${member.userId}`}
                className="text-xs uppercase tracking-wide text-muted-foreground"
              >
                Email
              </Label>
              <Input
                id={`em-${member.userId}`}
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                disabled={isSaving}
              />
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">
                Affiliate
              </Label>
              <AffiliateCombobox
                value={affiliateInput}
                onChange={setAffiliateInput}
                placeholder="Search or enter affiliate..."
                disabled={isSaving}
              />
              <p className="text-[11px] text-muted-foreground">
                Leave empty and save to set as Independent.
              </p>
            </div>
            <div className="text-xs text-muted-foreground">
              Editing the name or email updates this user's account profile
              everywhere — not just in this competition.
            </div>
            <div className="flex items-center gap-2 pt-1">
              <Button onClick={handleSave} disabled={isSaving} size="sm">
                {isSaving ? "Saving..." : "Save"}
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={handleCancel}
                disabled={isSaving}
              >
                Cancel
              </Button>
            </div>
          </>
        ) : (
          <div className="space-y-2 text-sm">
            <div className="grid gap-1.5">
              <div className="flex gap-3">
                <span className="text-muted-foreground w-20 shrink-0">
                  Email
                </span>
                <span className="truncate">{member.email}</span>
              </div>
              <div className="flex gap-3">
                <span className="text-muted-foreground w-20 shrink-0">
                  Affiliate
                </span>
                <span
                  className={
                    affiliate ? "truncate" : "truncate text-muted-foreground"
                  }
                >
                  {displayAffiliate}
                </span>
              </div>
            </div>
            {onRemove && (
              <div className="flex justify-end pt-1">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={onRemove}
                  className="h-7 text-xs text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                >
                  <Trash2 className="h-3 w-3 mr-1" />
                  Remove from team
                </Button>
              </div>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  )
}

import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import {
  Check,
  Mail,
  Pencil,
  Plus,
  RefreshCcw,
  UserPlus,
  X,
} from "lucide-react"
import { useState } from "react"
import { toast } from "sonner"
import { AffiliateCombobox } from "@/components/registration/affiliate-combobox"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import {
  cancelPendingTeamInviteFn,
  resendTeamInviteAsOrganizerFn,
  updatePendingInviteAffiliateAsOrganizerFn,
} from "@/server-fns/organizer-athlete-fns"
import type { AthleteDetailPendingInvite } from "./types"

interface InviteSlotProps {
  variant: "invite"
  invite: AthleteDetailPendingInvite
  registrationId: string
  competitionId: string
  formatDate: (d: Date | string | null | undefined) => string
}

interface EmptySlotProps {
  variant: "empty"
  onAdd: () => void
  disabled?: boolean
}

type RosterSlotCardProps = InviteSlotProps | EmptySlotProps

export function RosterSlotCard(props: RosterSlotCardProps) {
  if (props.variant === "invite") return <InviteSlot {...props} />
  return <EmptySlot {...props} />
}

function InviteSlot({
  invite,
  registrationId,
  competitionId,
  formatDate,
}: InviteSlotProps) {
  const router = useRouter()
  const cancelInvite = useServerFn(cancelPendingTeamInviteFn)
  const refreshInvite = useServerFn(resendTeamInviteAsOrganizerFn)
  const updateAffiliate = useServerFn(updatePendingInviteAffiliateAsOrganizerFn)
  const [busy, setBusy] = useState(false)
  const [editingAffiliate, setEditingAffiliate] = useState(false)
  const [affiliateInput, setAffiliateInput] = useState(
    invite.affiliateName ?? "",
  )
  const [savingAffiliate, setSavingAffiliate] = useState(false)

  const isAccepted = invite.status === "accepted"
  const initial = (
    invite.guestName?.[0] ??
    invite.email[0] ??
    "?"
  ).toUpperCase()

  const handleCancel = async () => {
    setBusy(true)
    try {
      await cancelInvite({
        data: { invitationId: invite.id, competitionId, registrationId },
      })
      toast.success("Invite cancelled")
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to cancel invite",
      )
    } finally {
      setBusy(false)
    }
  }

  const handleResend = async () => {
    setBusy(true)
    try {
      await refreshInvite({
        data: { invitationId: invite.id, registrationId, competitionId },
      })
      toast.success("Invite resent")
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to resend invite",
      )
    } finally {
      setBusy(false)
    }
  }

  const handleSaveAffiliate = async () => {
    const trimmed = affiliateInput.trim()
    if (trimmed === (invite.affiliateName ?? "")) {
      setEditingAffiliate(false)
      return
    }
    setSavingAffiliate(true)
    try {
      await updateAffiliate({
        data: {
          invitationId: invite.id,
          registrationId,
          competitionId,
          affiliateName: trimmed || null,
        },
      })
      toast.success("Affiliate saved — applies when teammate completes sign-up")
      setEditingAffiliate(false)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to save affiliate",
      )
    } finally {
      setSavingAffiliate(false)
    }
  }

  const displayAffiliate = invite.affiliateName || "Independent"

  return (
    <Card className="border-dashed bg-muted/20">
      <CardContent className="p-6 flex flex-col gap-4 h-full">
        <div className="flex items-start gap-3 min-w-0">
          <div className="h-11 w-11 shrink-0 rounded-full border-2 border-dashed border-border flex items-center justify-center bg-background text-sm font-semibold text-muted-foreground">
            {initial}
          </div>
          <div className="min-w-0 flex-1">
            <div className="font-semibold truncate text-foreground/90">
              {invite.guestName || invite.email}
            </div>
            <div className="mt-1">
              {isAccepted ? (
                <Badge
                  variant="outline"
                  className="text-xs bg-green-50 text-green-700 border-green-300 dark:bg-green-950 dark:text-green-300 dark:border-green-800"
                  title="They filled out the registration form. Now they need to create an account before joining the team."
                >
                  Awaiting sign-up
                </Badge>
              ) : (
                <Badge
                  variant="outline"
                  className="text-xs bg-amber-50 text-amber-700 border-amber-300 dark:bg-amber-950 dark:text-amber-300 dark:border-amber-800"
                  title="Invitation email has been sent — waiting for the teammate to open the link."
                >
                  Awaiting response
                </Badge>
              )}
            </div>
          </div>
        </div>

        <div className="space-y-2 text-sm">
          {invite.guestName && (
            <div className="flex gap-3">
              <span className="text-muted-foreground w-20 shrink-0">Email</span>
              <span className="truncate flex items-center gap-1.5">
                <Mail className="h-3 w-3 text-muted-foreground shrink-0" />
                {invite.email}
              </span>
            </div>
          )}
          <div className="flex gap-3">
            <span className="text-muted-foreground w-20 shrink-0">Sent</span>
            <span className="text-muted-foreground">
              {formatDate(invite.createdAt)}
            </span>
          </div>
          {invite.expiresAt && (
            <div className="flex gap-3">
              <span className="text-muted-foreground w-20 shrink-0">
                Expires
              </span>
              <span className="text-muted-foreground">
                {formatDate(invite.expiresAt)}
              </span>
            </div>
          )}
          <div className="flex items-start gap-3">
            <span className="text-muted-foreground w-20 shrink-0 pt-1">
              Affiliate
            </span>
            <div className="min-w-0 flex-1">
              {editingAffiliate ? (
                <div className="space-y-2">
                  <AffiliateCombobox
                    value={affiliateInput}
                    onChange={setAffiliateInput}
                    placeholder="Search or enter affiliate..."
                    disabled={savingAffiliate}
                  />
                  <div className="flex items-center gap-1.5">
                    <Button
                      size="sm"
                      onClick={handleSaveAffiliate}
                      disabled={savingAffiliate}
                      className="h-7"
                    >
                      <Check className="h-3.5 w-3.5 mr-1" />
                      {savingAffiliate ? "Saving..." : "Save"}
                    </Button>
                    <Button
                      size="sm"
                      variant="ghost"
                      onClick={() => {
                        setAffiliateInput(invite.affiliateName ?? "")
                        setEditingAffiliate(false)
                      }}
                      disabled={savingAffiliate}
                      className="h-7"
                    >
                      Cancel
                    </Button>
                  </div>
                </div>
              ) : (
                <button
                  type="button"
                  onClick={() => setEditingAffiliate(true)}
                  className="group inline-flex items-center gap-1.5 text-left -ml-1 px-1 rounded hover:bg-muted/60"
                >
                  <span
                    className={
                      invite.affiliateName ? "" : "text-muted-foreground italic"
                    }
                  >
                    {displayAffiliate}
                  </span>
                  <Pencil className="h-3 w-3 text-muted-foreground opacity-0 group-hover:opacity-100" />
                </button>
              )}
            </div>
          </div>
        </div>

        <div className="flex items-center gap-1.5 mt-auto pt-1">
          <Button
            variant="outline"
            size="sm"
            onClick={handleResend}
            disabled={busy}
            className="h-8"
          >
            <RefreshCcw className="h-3.5 w-3.5 mr-1.5" />
            Resend
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleCancel}
            disabled={busy}
            className="h-8 text-destructive hover:text-destructive hover:bg-destructive/10"
          >
            <X className="h-3.5 w-3.5 mr-1.5" />
            Cancel
          </Button>
        </div>
      </CardContent>
    </Card>
  )
}

function EmptySlot({ onAdd, disabled }: EmptySlotProps) {
  return (
    <button
      type="button"
      onClick={onAdd}
      disabled={disabled}
      className="group relative flex min-h-[180px] flex-col items-center justify-center gap-2 rounded-lg border border-dashed border-border bg-muted/10 p-6 text-center transition-colors hover:border-primary/50 hover:bg-primary/5 disabled:cursor-not-allowed disabled:opacity-50 disabled:hover:border-border disabled:hover:bg-muted/10"
    >
      <div className="h-11 w-11 rounded-full border-2 border-dashed border-border flex items-center justify-center bg-background text-muted-foreground group-hover:border-primary/50 group-hover:text-primary transition-colors">
        <Plus className="h-5 w-5" />
      </div>
      <div className="space-y-0.5">
        <div className="text-sm font-medium text-foreground/90">Open slot</div>
        <div className="text-xs text-muted-foreground flex items-center gap-1 justify-center">
          <UserPlus className="h-3 w-3" />
          Add teammate
        </div>
      </div>
    </button>
  )
}

input.content:
import { useRouter } from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { Check, Clock, Pencil, UserCheck, X } from "lucide-react"
import { useState } from "react"
import { toast } from "sonner"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { updateRegistrationAnswerFn } from "@/server-fns/organizer-athlete-fns"
import {
  type AthleteDetailMember,
  type AthleteDetailPendingInvite,
  type AthleteDetailQuestion,
  memberDisplayName,
  memberInitials,
} from "./types"

function parseOptions(opts: string | null): string[] | null {
  if (!opts) return null
  try {
    const parsed = JSON.parse(opts)
    return Array.isArray(parsed) ? (parsed as string[]) : null
  } catch {
    return null
  }
}

function inviteInitial(invite: AthleteDetailPendingInvite): string {
  return (invite.guestName?.[0] ?? invite.email[0] ?? "?").toUpperCase()
}

function inviteDisplayName(invite: AthleteDetailPendingInvite): string {
  return invite.guestName?.trim() || invite.email
}

type Participant =
  | { kind: "member"; member: AthleteDetailMember }
  | { kind: "invite"; invite: AthleteDetailPendingInvite }

interface AnswersSectionProps {
  registrationId: string
  competitionId: string
  questions: AthleteDetailQuestion[]
  answers: Record<string, string> // `${userId}:${questionId}` -> answer
  members: AthleteDetailMember[]
  pendingInvites: AthleteDetailPendingInvite[]
  isTeamDivision: boolean
}

export function AnswersSection({
  registrationId,
  competitionId,
  questions,
  answers,
  members,
  pendingInvites,
  isTeamDivision,
}: AnswersSectionProps) {
  return (
    <Card>
      <CardHeader>
        <CardTitle>Registration Answers</CardTitle>
        <CardDescription>
          Per-person answers from the registration form. Click a row to edit;
          clearing a field deletes the answer. Pending teammate answers are
          read-only until sign-up completes.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-7">
        {questions.map((question) => {
          const participants = buildParticipants({
            question,
            members,
            pendingInvites,
            isTeamDivision,
          })

          const totals = participants.reduce(
            (acc, p) => {
              const ans = getAnswerFor(p, question.id, answers)
              if (ans) acc.answered += 1
              acc.total += 1
              return acc
            },
            { answered: 0, total: 0 },
          )

          const allAnswered =
            totals.total > 0 && totals.answered === totals.total

          return (
            <div key={question.id} className="space-y-3">
              {/* Question header */}
              <div className="flex items-start justify-between gap-4 flex-wrap">
                <div className="space-y-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <div className="font-semibold">{question.label}</div>
                    <Badge variant="secondary" className="text-[10px]">
                      {question.type}
                    </Badge>
                    {question.required && (
                      <Badge variant="outline" className="text-[10px]">
                        Required
                      </Badge>
                    )}
                  </div>
                  {question.helpText && (
                    <p className="text-xs text-muted-foreground max-w-prose">
                      {question.helpText}
                    </p>
                  )}
                </div>
                {totals.total > 0 && (
                  <span
                    className={
                      "font-mono text-[10px] uppercase tracking-[0.22em] tabular-nums shrink-0 " +
                      (allAnswered
                        ? "text-green-600 dark:text-green-400"
                        : "text-muted-foreground")
                    }
                  >
                    {totals.answered}/{totals.total} answered
                  </span>
                )}
              </div>

              {/* Per-participant rows */}
              <ul className="divide-y rounded-md border">
                {participants.map((p) =>
                  p.kind === "member" ? (
                    <MemberAnswerRow
                      key={`${question.id}-m-${p.member.userId}`}
                      registrationId={registrationId}
                      competitionId={competitionId}
                      question={question}
                      member={p.member}
                      currentAnswer={
                        answers[`${p.member.userId}:${question.id}`] ?? ""
                      }
                    />
                  ) : (
                    <InviteAnswerRow
                      key={`${question.id}-i-${p.invite.id}`}
                      question={question}
                      invite={p.invite}
                    />
                  ),
                )}
              </ul>
            </div>
          )
        })}
      </CardContent>
    </Card>
  )
}

function buildParticipants({
  question,
  members,
  pendingInvites,
  isTeamDivision,
}: {
  question: AthleteDetailQuestion
  members: AthleteDetailMember[]
  pendingInvites: AthleteDetailPendingInvite[]
  isTeamDivision: boolean
}): Participant[] {
  const activeMembers = members.filter((m) => m.isActive)

  // Captain-only questions (forTeammates=false) never include pending invites.
  if (!question.forTeammates) {
    const captainOnly = activeMembers.filter((m) => m.isCaptain)
    const base = captainOnly.length > 0 ? captainOnly : activeMembers
    return base.map((m) => ({ kind: "member", member: m }))
  }

  const memberParticipants: Participant[] = activeMembers.map((m) => ({
    kind: "member",
    member: m,
  }))

  if (!isTeamDivision) return memberParticipants

  const inviteParticipants: Participant[] = pendingInvites.map((invite) => ({
    kind: "invite",
    invite,
  }))
  return [...memberParticipants, ...inviteParticipants]
}

function getAnswerFor(
  p: Participant,
  questionId: string,
  answers: Record<string, string>,
): string {
  if (p.kind === "member") {
    return answers[`${p.member.userId}:${questionId}`] ?? ""
  }
  return (
    p.invite.pendingAnswers?.find((a) => a.questionId === questionId)?.answer ??
    ""
  )
}

// ---------------------------------------------------------------------------
// Member row (editable inline)
// ---------------------------------------------------------------------------

interface MemberAnswerRowProps {
  registrationId: string
  competitionId: string
  question: AthleteDetailQuestion
  member: AthleteDetailMember
  currentAnswer: string
}

function MemberAnswerRow({
  registrationId,
  competitionId,
  question,
  member,
  currentAnswer,
}: MemberAnswerRowProps) {
  const router = useRouter()
  const updateAnswer = useServerFn(updateRegistrationAnswerFn)
  const [editing, setEditing] = useState(false)
  const [value, setValue] = useState(currentAnswer)
  const [isSaving, setIsSaving] = useState(false)

  const handleSave = async () => {
    setIsSaving(true)
    try {
      await updateAnswer({
        data: {
          registrationId,
          competitionId,
          userId: member.userId,
          questionId: question.id,
          answer: value,
        },
      })
      toast.success("Answer saved")
      setEditing(false)
      router.invalidate()
    } catch (error) {
      toast.error(
        error instanceof Error ? error.message : "Failed to save answer",
      )
    } finally {
      setIsSaving(false)
    }
  }

  const handleCancel = () => {
    setValue(currentAnswer)
    setEditing(false)
  }

  const options = parseOptions(question.options)

  return (
    <li className="p-3">
      <div className="flex items-start gap-3">
        <Avatar className="h-8 w-8 shrink-0">
          <AvatarImage
            src={member.avatar ?? undefined}
            alt={memberDisplayName(member)}
          />
          <AvatarFallback className="text-[11px] font-semibold">
            {memberInitials(member)}
          </AvatarFallback>
        </Avatar>

        <div className="min-w-0 flex-1">
          <div className="flex items-center gap-2 flex-wrap mb-1">
            <span className="text-sm font-medium truncate">
              {memberDisplayName(member)}
            </span>
            <Badge
              variant={member.isCaptain ? "secondary" : "outline"}
              className="text-[10px] uppercase tracking-wide"
            >
              {member.isCaptain ? "Captain" : "Teammate"}
            </Badge>
          </div>

          {editing ? (
            <div className="flex items-start gap-2 mt-1">
              {question.type === "select" && options ? (
                <div className="flex items-center gap-1 flex-1 max-w-md">
                  <Select value={value} onValueChange={setValue}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select an option" />
                    </SelectTrigger>
                    <SelectContent>
                      {options.map((opt) => (
                        <SelectItem key={opt} value={opt}>
                          {opt}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {value && (
                    <Button
                      size="icon"
                      variant="ghost"
                      type="button"
                      onClick={() => setValue("")}
                      disabled={isSaving}
                      aria-label="Clear selection"
                      className="h-9 w-9 shrink-0"
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  )}
                </div>
              ) : question.type === "number" ? (
                <Input
                  type="number"
                  value={value}
                  onChange={(e) => setValue(e.target.value)}
                  disabled={isSaving}
                  className="max-w-md"
                />
              ) : value.length > 60 ? (
                <Textarea
                  value={value}
                  onChange={(e) => setValue(e.target.value)}
                  disabled={isSaving}
                  rows={3}
                  className="max-w-md"
                />
              ) : (
                <Input
                  value={value}
                  onChange={(e) => setValue(e.target.value)}
                  disabled={isSaving}
                  className="max-w-md"
                />
              )}
              <Button
                size="icon"
                variant="outline"
                onClick={handleSave}
                disabled={isSaving}
                aria-label="Save answer"
                className="h-9 w-9 shrink-0"
              >
                <Check className="h-4 w-4" />
              </Button>
              <Button
                size="icon"
                variant="ghost"
                onClick={handleCancel}
                disabled={isSaving}
                aria-label="Cancel"
                className="h-9 w-9 shrink-0"
              >
                <X className="h-4 w-4" />
              </Button>
            </div>
          ) : (
            <button
              type="button"
              onClick={() => setEditing(true)}
              className="group flex w-full items-start justify-between gap-3 rounded-md text-left -mx-1 px-1 py-1 hover:bg-muted/60"
            >
              <span
                className={
                  currentAnswer
                    ? "text-sm break-words min-w-0 flex-1"
                    : "text-sm italic text-muted-foreground/70 min-w-0 flex-1"
                }
              >
                {currentAnswer || "Not answered"}
              </span>
              <Pencil className="h-3.5 w-3.5 text-muted-foreground opacity-0 group-hover:opacity-100 transition-opacity mt-0.5 shrink-0" />
            </button>
          )}
        </div>
      </div>
    </li>
  )
}

// ---------------------------------------------------------------------------
// Pending-invite row (read-only)
// ---------------------------------------------------------------------------

interface InviteAnswerRowProps {
  question: AthleteDetailQuestion
  invite: AthleteDetailPendingInvite
}

